package com.chaobo.scm.supplier.application.profile;import com.chaobo.scm.common.integration.MasterDataCollaborationApi;import com.chaobo.scm.supplier.application.integration.IntegrationCommandEnqueuer;import com.chaobo.scm.supplier.application.masterdata.MasterDataSnapshotPort;import com.chaobo.scm.supplier.application.shared.CommandContext;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class SupplierLifecycleApplicationService{private final MasterDataSnapshotPort snapshots;private final IntegrationCommandEnqueuer integrations;public SupplierLifecycleApplicationService(MasterDataSnapshotPort snapshots,IntegrationCommandEnqueuer integrations){this.snapshots=snapshots;this.integrations=integrations;}@Transactional public void change(long supplierId,int targetStatus,String reason,CommandContext context){context.requirePermission("supplier:lifecycle:manage");context.requireSupplierScope(supplierId);var supplier=snapshots.findSupplier(supplierId).orElseThrow(()->new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.NOT_FOUND,"供应商不存在"));if(targetStatus<3||targetStatus>5)throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.VALIDATION_FAILED,"目标状态必须为启用、冻结或停用");if(reason==null||reason.isBlank())throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.VALIDATION_FAILED,"状态变更原因不能为空");integrations.enqueue("MDM_CHANGE_SUPPLIER_STATUS","SUPPLIER",supplierId,(int)supplier.sourceVersion(),"MDM",new MasterDataCollaborationApi.ChangeSupplierStatusCommand("MDM-STATUS-"+supplierId+"-"+supplier.sourceVersion()+"-"+targetStatus,supplierId,targetStatus,reason));}}
